// EDTMRS - Policy Manager Page
// Manage device whitelist and blocklist
import React, { useState, useEffect, useCallback } from 'react';
import { actionsAPI } from '../utils/api';

export default function PolicyPage() {
  const [whitelist, setWhitelist] = useState([]);
  const [blocked,   setBlocked]   = useState([]);
  const [tab, setTab]             = useState('whitelist');
  const [loading, setLoading]     = useState(true);
  const [toast, setToast]         = useState('');

  const fetchAll = useCallback(async () => {
    setLoading(true);
    try {
      const [wl, bl] = await Promise.all([actionsAPI.getWhitelist(), actionsAPI.getBlocked()]);
      setWhitelist(wl.data.whitelist);
      setBlocked(bl.data.blocked_devices);
    } finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const removeWhitelist = async (id) => {
    await actionsAPI.removeWhitelist(id);
    setToast('Removed from whitelist');
    setTimeout(() => setToast(''), 3000);
    fetchAll();
  };

  const unblock = async (id) => {
    await actionsAPI.unblockDevice(id);
    setToast('Device unblocked');
    setTimeout(() => setToast(''), 3000);
    fetchAll();
  };

  const data = tab === 'whitelist' ? whitelist : blocked;
  const emptyMsg = tab === 'whitelist'
    ? 'No whitelisted devices. Use Device Monitor → Actions → Whitelist.'
    : 'No blocked devices. Use Device Monitor → Actions → Block.';

  return (
    <div className="space-y-5">
      {toast && (
        <div className="fixed top-5 right-5 z-50 px-4 py-3 bg-emerald-600/20 border border-emerald-500/40 text-emerald-400 rounded-xl text-sm shadow-xl">
          ✓ {toast}
        </div>
      )}

      <div>
        <h1 className="text-xl font-bold text-white">Policy Manager</h1>
        <p className="text-gray-500 text-sm mt-0.5">Manage device whitelist and block rules</p>
      </div>

      {/* Tabs */}
      <div className="flex gap-2">
        <button onClick={() => setTab('whitelist')}
          className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
            tab === 'whitelist' ? 'bg-emerald-600 text-white' : 'bg-[#0f1629] border border-[#1e2d4d] text-gray-400 hover:text-white'
          }`}>
          ✓ Whitelist ({whitelist.length})
        </button>
        <button onClick={() => setTab('blocked')}
          className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
            tab === 'blocked' ? 'bg-red-600 text-white' : 'bg-[#0f1629] border border-[#1e2d4d] text-gray-400 hover:text-white'
          }`}>
          ⊘ Blocked ({blocked.length})
        </button>
      </div>

      {/* Info banner */}
      <div className={`px-4 py-3 rounded-xl border text-sm ${
        tab === 'whitelist'
          ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400'
          : 'bg-red-500/10 border-red-500/30 text-red-400'
      }`}>
        {tab === 'whitelist'
          ? '✓ Whitelisted devices are marked as SAFE and will not generate alerts.'
          : '⊘ Blocked devices are marked as CRITICAL when connected. Use Device Monitor → Actions to block new devices.'}
      </div>

      {/* Table */}
      <div className="bg-[#0f1629] border border-[#1e2d4d] rounded-xl overflow-hidden">
        {loading ? (
          <div className="flex justify-center py-16">
            <div className="w-6 h-6 border-2 border-blue-500/30 border-t-blue-400 rounded-full animate-spin" />
          </div>
        ) : !data.length ? (
          <div className="text-center py-16 text-gray-600">
            <div className="text-2xl mb-2">{tab === 'whitelist' ? '✓' : '⊘'}</div>
            <div className="text-sm">{emptyMsg}</div>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-[#1e2d4d] text-gray-500 text-xs uppercase tracking-wider">
                  <th className="px-5 py-3 text-left">Device Name</th>
                  <th className="px-5 py-3 text-left">VID</th>
                  <th className="px-5 py-3 text-left">PID</th>
                  <th className="px-5 py-3 text-left">Serial</th>
                  <th className="px-5 py-3 text-left">{tab === 'whitelist' ? 'Notes' : 'Reason'}</th>
                  <th className="px-5 py-3 text-left">Added</th>
                  <th className="px-5 py-3 text-left">Action</th>
                </tr>
              </thead>
              <tbody>
                {data.map((d) => (
                  <tr key={d.id} className="border-b border-[#1a2035] hover:bg-white/2 transition-colors">
                    <td className="px-5 py-3 text-white font-medium">{d.device_name || '—'}</td>
                    <td className="px-5 py-3 font-mono text-gray-300 text-xs">{d.vendor_id || '—'}</td>
                    <td className="px-5 py-3 font-mono text-gray-300 text-xs">{d.product_id || '—'}</td>
                    <td className="px-5 py-3 font-mono text-gray-400 text-xs max-w-[120px] truncate">{d.serial_number || '—'}</td>
                    <td className="px-5 py-3 text-gray-500 text-xs max-w-[200px] truncate">
                      {(tab === 'whitelist' ? d.notes : d.reason) || '—'}
                    </td>
                    <td className="px-5 py-3 text-gray-500 text-xs whitespace-nowrap">
                      {d.created_at ? new Date(d.created_at).toLocaleDateString() : '—'}
                    </td>
                    <td className="px-5 py-3">
                      {tab === 'whitelist' ? (
                        <button onClick={() => removeWhitelist(d.id)}
                          className="px-2.5 py-1 bg-red-600/20 hover:bg-red-600/30 border border-red-500/40 text-red-400 rounded-lg text-xs transition-all">
                          Remove
                        </button>
                      ) : (
                        <button onClick={() => unblock(d.id)}
                          className="px-2.5 py-1 bg-emerald-600/20 hover:bg-emerald-600/30 border border-emerald-500/40 text-emerald-400 rounded-lg text-xs transition-all">
                          Unblock
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
